+
+/// Trait for reranking a set of candidate documents against a query.
+pub trait Reranker: Send + Sync {
+    fn rerank(&self, query: &str, docs: Vec<ScoredDoc>) -> Result<Vec<ScoredDoc>, RerankError>;
